      + '</svg>';
  }

  function placeMarkers() {
    document.querySelectorAll('.wmap-marker').forEach(function(e) { e.remove(); });
    var inner = document.getElementById('wmap-inner');

    MARKERS.forEach(function(m) {
      var el = document.createElement('div');
      el.className  = 'wmap-marker';
      el.style.left = m.left;
      el.style.top  = m.top;
      el.innerHTML  =
        '<div class="wmap-tooltip">'
          + '<span class="wmap-tip-country">' + m.label + '</span>'
          + '<span class="wmap-tip-city ' + m.cls + '">' + m.city + '</span>'
        + '</div>'
        + '<div class="wmap-pin">' + makePinSVG(m.color) + '</div>'
        + '<div class="wmap-dot" style="background:' + m.color + ';"></div>';

      inner.appendChild(el);
    });
  }

  placeMarkers();
  window.addEventListener('resize', placeMarkers);

  function autoCycle() {
    var markers = document.querySelectorAll('.wmap-marker');
    var current = 0;
    function hideCurrentThenShow() {
      markers = document.querySelectorAll('.wmap-marker');
      markers.forEach(function(m) { m.classList.remove('active'); });
      setTimeout(function() {
        if (markers.length > 0) {
          markers[current].classList.add('active');
          current = (current + 1) % markers.length;
        }
      }, 400);
    }
    hideCurrentThenShow();
    setInterval(hideCurrentThenShow, 3000);
  }

  autoCycle();

